#nullable enable // autogenerated

using MVZ2Logic.Definitions;
using PVZEngine.Base;

namespace MVZ2Logic.Options
{
    public abstract class OptionWidgetDefinition : Definition
    {
        public OptionWidgetDefinition(string nsp, string name) : base(nsp, name)
        {
        }
        public virtual bool ShouldEnable(IOptionContext context) => true;
        public abstract OptionWidgetType GetItemType();
        public sealed override string GetDefinitionType() => LogicDefinitionTypes.OPTION_WIDGET;
    }
    public enum OptionItemType
    {
        Boolean,
        Int,
        Float,
        String,
        ID
    }
    public enum OptionWidgetType
    {
        Button,
        Toggle,
        Dropdown,
        Slider,
    }
}
